export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface ProcessingState {
  isProcessing: boolean;
  error: string | null;
}

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:image/png;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
    reader.readAsDataURL(file);
  });
};

export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

export const decodeBase64 = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const encodeToPCM = (bytes: Uint8Array): string => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
};

export const createPCMBlob = (data: Float32Array): { data: string; mimeType: string } => {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encodeToPCM(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
};

import { GoogleGenAI, Modality } from "@google/genai";
import { decodeBase64, decodeAudioData } from "./utils";

const API_KEY = process.env.API_KEY || '';

// We create a fresh instance per call to ensure key validity if it changes, 
// though usually global is fine for single-session apps.
const getAI = () => new GoogleGenAI({ apiKey: API_KEY });

export const editImageWithGemini = async (base64Image: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();

  // Using gemini-2.5-flash-image for image editing tasks
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Image,
            mimeType: mimeType,
          },
        },
        {
          text: prompt || "Enhance this image",
        },
      ],
    },
    // No specific config needed for basic edits, model handles it via prompt
  });

  // Extract image from response
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image returned from Gemini.");
};

export const analyzeVideoWithGemini = async (base64Video: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();

  // Using gemini-3-pro-preview for complex video reasoning
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Video,
            mimeType: mimeType,
          },
        },
        {
          text: prompt || "Analyze this video in detail.",
        },
      ],
    },
  });

  return response.text || "No analysis generated.";
};

export const transcribeAudioWithGemini = async (base64Audio: string, mimeType: string): Promise<string> => {
  const ai = getAI();

  // Using gemini-3-flash-preview for fast audio transcription
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Audio,
            mimeType: mimeType,
          },
        },
        {
          text: "Transcribe the audio exactly as spoken.",
        },
      ],
    },
  });

  return response.text || "Transcription failed.";
};

export const generateSpeechWithGemini = async (text: string, voiceName: 'Kore' | 'Puck' | 'Fenrir' | 'Zephyr' = 'Kore'): Promise<void> => {
  const ai = getAI();

  // Using gemini-2.5-flash-preview-tts for TTS
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const audioBuffer = await decodeAudioData(
    decodeBase64(base64Audio),
    outputAudioContext,
    24000,
    1,
  );

  const source = outputAudioContext.createBufferSource();
  source.buffer = audioBuffer;
  source.connect(outputAudioContext.destination);
  source.start();
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPCMBlob, decodeBase64, decodeAudioData } from '../services/utils';
import { Mic, MicOff, Activity, Radio, XCircle } from 'lucide-react';

const API_KEY = process.env.API_KEY || '';

const LiveAvatar: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'active' | 'error'>('idle');
  const [isSpeaking, setIsSpeaking] = useState(false); // Visualizer trigger

  // Refs for audio handling to persist across renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  const cleanup = () => {
    if (sessionRef.current) {
      sessionRef.current.close(); // Although close method might not exist on the promise directly, we rely on closing the connection from the object if available or just resetting state.
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
        try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();

    // Close audio contexts
    if (audioContextRef.current) audioContextRef.current.close();
    if (inputContextRef.current) inputContextRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());

    audioContextRef.current = null;
    inputContextRef.current = null;
    streamRef.current = null;

    setIsConnected(false);
    setStatus('idle');
    setIsSpeaking(false);
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  const startSession = async () => {
    try {
      setStatus('connecting');
      const ai = new GoogleGenAI({ apiKey: API_KEY });

      // Setup Audio Output
      const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputAudioContext;
      const outputNode = outputAudioContext.createGain();
      outputNode.connect(outputAudioContext.destination);

      // Setup Audio Input
      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inputAudioContext;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const source = inputAudioContext.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

      nextStartTimeRef.current = 0;

      // Connect to Gemini Live API
      // Using gemini-2.5-flash-native-audio-preview-09-2025
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: "You are 'Nova', a high-energy, futuristic AI companion in the OmniVerse. You are enthusiastic, helpful, and love creativity. Keep responses concise and engaging.",
        },
        callbacks: {
            onopen: () => {
                setStatus('active');
                setIsConnected(true);

                // Connect microphone stream
                scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    const pcmBlob = createPCMBlob(inputData);

                    sessionPromise.then((session) => {
                        session.sendRealtimeInput({ media: pcmBlob });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

                if (base64Audio) {
                    setIsSpeaking(true);
                    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);

                    const audioBuffer = await decodeAudioData(
                        decodeBase64(base64Audio),
                        outputAudioContext,
                        24000,
                        1
                    );

                    const sourceNode = outputAudioContext.createBufferSource();
                    sourceNode.buffer = audioBuffer;
                    sourceNode.connect(outputNode);

                    sourceNode.addEventListener('ended', () => {
                        sourcesRef.current.delete(sourceNode);
                        if (sourcesRef.current.size === 0) setIsSpeaking(false);
                    });

                    sourceNode.start(nextStartTimeRef.current);
                    nextStartTimeRef.current += audioBuffer.duration;
                    sourcesRef.current.add(sourceNode);
                }

                if (message.serverContent?.interrupted) {
                    sourcesRef.current.forEach(s => s.stop());
                    sourcesRef.current.clear();
                    nextStartTimeRef.current = 0;
                    setIsSpeaking(false);
                }
            },
            onclose: () => {
                setStatus('idle');
                setIsConnected(false);
            },
            onerror: (err) => {
                console.error(err);
                setStatus('error');
            }
        }
      });

      sessionRef.current = await sessionPromise;

    } catch (e) {
      console.error("Failed to connect:", e);
      setStatus('error');
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full w-full p-8 bg-black/40 backdrop-blur-md rounded-3xl border border-white/10 shadow-[0_0_50px_rgba(0,243,255,0.1)]">

        {/* Visualizer Circle */}
        <div className={`relative w-64 h-64 mb-8 flex items-center justify-center rounded-full transition-all duration-500 ${isSpeaking ? 'scale-110 shadow-[0_0_80px_#00f3ff]' : 'shadow-[0_0_20px_rgba(255,255,255,0.1)]'}`}>
            <div className={`absolute inset-0 rounded-full border-4 border-dashed border-neon-blue ${status === 'connecting' ? 'animate-spin' : ''}`}></div>
            <div className="absolute inset-4 rounded-full bg-gradient-to-tr from-gray-900 to-black flex items-center justify-center overflow-hidden">
                {status === 'active' ? (
                     <div className="w-full h-16 flex items-center justify-center gap-2">
                        {[1,2,3,4,5].map(i => (
                            <div key={i} className={`w-3 bg-neon-blue rounded-full transition-all duration-100 ${isSpeaking ? 'animate-[pulse_0.5s_ease-in-out_infinite]' : 'h-2'}`} style={{ height: isSpeaking ? `${Math.random() * 40 + 10}px` : '4px', animationDelay: `${i * 0.1}s` }} />
                        ))}
                     </div>
                ) : (
                    <Activity className="w-16 h-16 text-gray-600" />
                )}
            </div>
        </div>

        <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-neon-blue to-neon-purple">
            Nova Live
        </h2>
        <p className="text-gray-400 mb-8 text-center max-w-md">
            Your real-time AI companion. Talk naturally to brainstorm ideas, ask questions, or just hang out.
        </p>

        {status === 'error' && (
            <div className="mb-4 text-neon-pink flex items-center gap-2">
                <XCircle size={20} />
                <span>Connection failed. Please try again.</span>
            </div>
        )}

        {!isConnected ? (
            <button
                onClick={startSession}
                disabled={status === 'connecting'}
                className="group relative px-8 py-4 bg-white text-black font-bold rounded-full overflow-hidden hover:scale-105 transition-transform"
            >
                <div className="absolute inset-0 bg-gradient-to-r from-neon-blue to-neon-purple opacity-0 group-hover:opacity-100 transition-opacity" />
                <div className="relative flex items-center gap-2 z-10 group-hover:text-white">
                    <Mic size={24} />
                    <span>{status === 'connecting' ? 'Initializing...' : 'Start Voice Chat'}</span>
                </div>
            </button>
        ) : (
            <button
                onClick={cleanup}
                className="px-8 py-4 bg-red-500/20 text-red-500 border border-red-500 rounded-full font-bold hover:bg-red-500 hover:text-white transition-all flex items-center gap-2"
            >
                <MicOff size={24} />
                <span>Disconnect</span>
            </button>
        )}

        {isConnected && (
            <div className="mt-6 flex items-center gap-2 text-xs text-neon-blue animate-pulse">
                <Radio size={12} />
                LIVE CONNECTION SECURE
            </div>
        )}
    </div>
  );
};

export default LiveAvatar;

import React, { useState } from 'react';
import { editImageWithGemini } from '../services/gemini';
import { fileToBase64 } from '../services/utils';
import { Upload, Sparkles, Wand2, Image as ImageIcon } from 'lucide-react';

const ImageStudio: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      const base64 = await fileToBase64(file);
      setPreview(`data:${file.type};base64,${base64}`);
      setResultImage(null);
    }
  };

  const handleGenerate = async () => {
    if (!selectedFile || !prompt) return;

    setIsLoading(true);
    try {
      const base64 = await fileToBase64(selectedFile);
      // Calls gemini-2.5-flash-image
      const editedImage = await editImageWithGemini(base64, selectedFile.type, prompt);
      setResultImage(editedImage);
    } catch (error) {
      console.error("Error editing image:", error);
      alert("Failed to edit image. Try a different prompt.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col lg:flex-row gap-6 p-6">

      {/* Controls */}
      <div className="flex-1 bg-white/5 border border-white/10 rounded-2xl p-6 flex flex-col gap-6">
        <div>
          <h2 className="text-2xl font-bold text-white mb-2 flex items-center gap-2">
            <Wand2 className="text-neon-purple" /> Avatar Studio
          </h2>
          <p className="text-gray-400 text-sm">Upload an asset and use AI to transform it.</p>
        </div>

        <div className="space-y-4">
          <label className="block w-full cursor-pointer group">
            <div className="border-2 border-dashed border-gray-600 rounded-xl p-8 flex flex-col items-center justify-center transition-colors group-hover:border-neon-purple bg-black/20">
              <Upload className="text-gray-400 mb-2 group-hover:text-neon-purple" />
              <span className="text-gray-400 text-sm group-hover:text-white">Click to upload image</span>
            </div>
            <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
          </label>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">Magic Prompt</label>
            <textarea
              className="w-full bg-black/40 border border-gray-700 rounded-lg p-3 text-white focus:border-neon-purple focus:ring-1 focus:ring-neon-purple outline-none transition-all resize-none"
              rows={3}
              placeholder="e.g., Make it look like a retro 8-bit game character, or Add a neon glowing aura"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={!selectedFile || !prompt || isLoading}
            className={`w-full py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${
              !selectedFile || !prompt || isLoading
                ? 'bg-gray-700 text-gray-500 cursor-not-allowed'
                : 'bg-gradient-to-r from-neon-purple to-neon-pink text-white hover:shadow-[0_0_20px_rgba(188,19,254,0.4)]'
            }`}
          >
            {isLoading ? <span className="animate-spin">⏳</span> : <Sparkles size={18} />}
            {isLoading ? 'Transforming...' : 'Magic Edit'}
          </button>
        </div>
      </div>

      {/* Preview Area */}
      <div className="flex-[2] bg-black/40 rounded-2xl border border-white/10 p-6 flex items-center justify-center relative overflow-hidden">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full h-full">
            {/* Original */}
            <div className="relative rounded-xl overflow-hidden bg-black/50 flex items-center justify-center border border-white/5">
                {preview ? (
                    <img src={preview} alt="Original" className="max-h-full max-w-full object-contain" />
                ) : (
                    <div className="text-gray-600 flex flex-col items-center">
                        <ImageIcon size={48} className="mb-2 opacity-50" />
                        <span>Original Asset</span>
                    </div>
                )}
                <div className="absolute top-2 left-2 bg-black/60 px-2 py-1 rounded text-xs text-white">Input</div>
            </div>

            {/* Result */}
            <div className="relative rounded-xl overflow-hidden bg-black/50 flex items-center justify-center border border-white/5">
                 {resultImage ? (
                    <img src={resultImage} alt="Edited" className="max-h-full max-w-full object-contain" />
                ) : (
                    <div className="text-gray-600 flex flex-col items-center">
                         <Sparkles size={48} className="mb-2 opacity-50 text-neon-purple" />
                        <span>AI Result</span>
                    </div>
                )}
                 <div className="absolute top-2 left-2 bg-neon-purple/80 px-2 py-1 rounded text-xs text-white">Output</div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ImageStudio;

import React, { useState } from 'react';
import { analyzeVideoWithGemini, transcribeAudioWithGemini, generateSpeechWithGemini } from '../services/gemini';
import { fileToBase64 } from '../services/utils';
import { Video, Mic, FileAudio, PlayCircle, FileText, Volume2 } from 'lucide-react';

const MediaLab: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'video' | 'audio' | 'tts'>('video');
  const [file, setFile] = useState<File | null>(null);
  const [output, setOutput] = useState('');
  const [loading, setLoading] = useState(false);
  const [ttsText, setTtsText] = useState('');

  const handleAnalyze = async () => {
    if (!file && activeTab !== 'tts') return;
    setLoading(true);
    setOutput('');

    try {
      if (activeTab === 'video' && file) {
        const base64 = await fileToBase64(file);
        // Calls gemini-3-pro-preview
        const text = await analyzeVideoWithGemini(base64, file.type, "Describe the key events and visual style of this video.");
        setOutput(text);
      } else if (activeTab === 'audio' && file) {
        const base64 = await fileToBase64(file);
        // Calls gemini-3-flash-preview
        const text = await transcribeAudioWithGemini(base64, file.type);
        setOutput(text);
      } else if (activeTab === 'tts') {
        // Calls gemini-2.5-flash-preview-tts
        if(!ttsText) return;
        await generateSpeechWithGemini(ttsText);
      }
    } catch (e) {
      console.error(e);
      setOutput("An error occurred during processing.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-full p-6 flex flex-col gap-6">

      {/* Navigation Tabs */}
      <div className="flex p-1 bg-white/10 rounded-xl w-fit">
        <button
          onClick={() => { setActiveTab('video'); setFile(null); setOutput(''); }}
          className={`px-6 py-2 rounded-lg flex items-center gap-2 font-medium transition-all ${activeTab === 'video' ? 'bg-neon-blue text-black shadow-lg' : 'text-gray-400 hover:text-white'}`}
        >
          <Video size={18} /> Video Intelligence
        </button>
        <button
          onClick={() => { setActiveTab('audio'); setFile(null); setOutput(''); }}
          className={`px-6 py-2 rounded-lg flex items-center gap-2 font-medium transition-all ${activeTab === 'audio' ? 'bg-neon-pink text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
        >
          <Mic size={18} /> Audio Transcriber
        </button>
        <button
          onClick={() => { setActiveTab('tts'); setFile(null); setOutput(''); }}
          className={`px-6 py-2 rounded-lg flex items-center gap-2 font-medium transition-all ${activeTab === 'tts' ? 'bg-neon-purple text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
        >
          <Volume2 size={18} /> Voice Synthesis
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">
        {/* Input Section */}
        <div className="bg-glass border border-white/10 rounded-2xl p-6 flex flex-col gap-4">
            <h3 className="text-xl font-bold mb-4">
                {activeTab === 'video' && 'Analyze Gameplay Footage'}
                {activeTab === 'audio' && 'Transcribe Voice Notes'}
                {activeTab === 'tts' && 'Text to Holographic Speech'}
            </h3>

            {activeTab !== 'tts' ? (
                <label className="flex-1 border-2 border-dashed border-gray-700 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-white transition-colors bg-black/20">
                    {file ? (
                        <div className="text-center">
                            {activeTab === 'video' ? <Video size={48} className="mx-auto mb-2 text-neon-blue"/> : <FileAudio size={48} className="mx-auto mb-2 text-neon-pink"/>}
                            <p className="font-bold">{file.name}</p>
                            <p className="text-sm text-gray-500">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                        </div>
                    ) : (
                        <div className="text-center text-gray-500">
                            <Upload className="mx-auto mb-2" />
                            <p>Upload {activeTab === 'video' ? 'Video (MP4)' : 'Audio (MP3/WAV)'}</p>
                        </div>
                    )}
                    <input 
                        type="file" 
                        className="hidden" 
                        accept={activeTab === 'video' ? "video/*" : "audio/*"}
                        onChange={(e) => setFile(e.target.files?.[0] || null)}
                    />
                </label>
            ) : (
                <textarea 
                    className="flex-1 bg-black/40 border border-gray-700 rounded-xl p-4 resize-none focus:border-neon-purple outline-none"
                    placeholder="Type something for the AI to say..."
                    value={ttsText}
                    onChange={(e) => setTtsText(e.target.value)}
                />
            )}

            <button
                onClick={handleAnalyze}
                disabled={loading || (activeTab !== 'tts' && !file) || (activeTab === 'tts' && !ttsText)}
                className="w-full py-4 bg-white text-black font-bold rounded-xl hover:scale-[1.02] active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {loading ? 'Processing with Gemini...' : (activeTab === 'tts' ? 'Speak Now' : 'Analyze Media')}
            </button>
        </div>

