import { GoogleGenAI, Modality, Type } from "@google/genai";
import { decodeBase64, decodeAudioData } from "./utils";
import { GameState } from "../types";

const API_KEY = process.env.API_KEY || '';

const getAI = () => new GoogleGenAI({ apiKey: API_KEY });

// --- IMAGE EDITING ---
export const editImageWithGemini = async (base64Image: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: mimeType } },
        { text: prompt || "Enhance this image" },
      ],
    },
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("No image returned.");
};

// --- VIDEO ANALYSIS ---
export const analyzeVideoWithGemini = async (base64Video: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Video, mimeType: mimeType } },
        { text: prompt || "Analyze this video in detail." },
      ],
    },
  });
  return response.text || "No analysis generated.";
};

// --- AUDIO TRANSCRIPTION ---
export const transcribeAudioWithGemini = async (base64Audio: string, mimeType: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Audio, mimeType: mimeType } },
        { text: "Transcribe the audio exactly as spoken." },
      ],
    },
  });
  return response.text || "Transcription failed.";
};

// --- TTS ---
export const generateSpeechWithGemini = async (text: string, voiceName: 'Kore' | 'Puck' | 'Fenrir' | 'Zephyr' = 'Kore'): Promise<void> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } } },
    },
  });
  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");
  const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), outputAudioContext, 24000, 1);
  const source = outputAudioContext.createBufferSource();
  source.buffer = audioBuffer;
  source.connect(outputAudioContext.destination);
  source.start();
};

// --- GAME ENGINE (OmniVerse Core) ---

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = getAI();
  // Using gemini-2.5-flash-image for speed and quality scene generation
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { text: `Cinematic, hyper-realistic, 8k, detailed concept art: ${prompt}` },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  return ""; // Return empty string if fails, UI should handle it
};

export const runGameTurn = async (history: any[], userAction: string): Promise<GameState> => {
  const ai = getAI();

  // Create a structured prompt context
  const context = `You are the OmniVerse Core, an advanced AI Game Master. 
  Your goal is to run an immersive, high-stakes RPG adventure.
  The genre is Sci-Fi / Cyberpunk.

  Current Action: ${userAction}

  Return the new game state based on the user's action and previous history.
  - 'health' is 0-100.
  - 'inventory' is a string array.
  - 'visualPrompt' should be a vivid description of the scene for an image generator (no text in image).
  - 'narrative' is the story text to show the user (keep it engaging, max 3 sentences).
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview', // Using Pro for complex logic and state management
    contents: [
        ...history,
        { role: 'user', parts: [{ text: context }] }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          location: { type: Type.STRING, description: "Current location name" },
          health: { type: Type.INTEGER, description: "Player health 0-100" },
          inventory: { type: Type.ARRAY, items: { type: Type.STRING } },
          narrative: { type: Type.STRING, description: "What happened" },
          visualPrompt: { type: Type.STRING, description: "Description for image generation" },
          gameOver: { type: Type.BOOLEAN },
        },
        required: ["location", "health", "inventory", "narrative", "visualPrompt", "gameOver"],
      },
    },
  });

  const jsonText = response.text || "{}";
  try {
      return JSON.parse(jsonText) as GameState;
  } catch (e) {
      console.error("Failed to parse game state", jsonText);
      throw new Error("Neural Link Disconnected (JSON Error)");
  }
};

import React, { useState, useEffect, useRef } from 'react';
