const INITIAL_STATE: GameState = {
  location: "Neon Slums - Sector 4",
  health: 100,
  inventory: ["Datapad", "Rusted Knife"],
  narrative: "You wake up in a rainy alleyway. Neon signs flicker above, reflecting in the puddles. You don't remember how you got here.",
  visualPrompt: "Cyberpunk rainy alleyway, neon signs, wet pavement, futuristic trash, dark atmosphere",
  gameOver: false
};

const StoryEngine: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(INITIAL_STATE);
  const [history, setHistory] = useState<any[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sceneImage, setSceneImage] = useState<string | null>(null);
  const [isGameStarted, setIsGameStarted] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initial Scene Load
  useEffect(() => {
    if (isGameStarted && !sceneImage) {
        generateImage(INITIAL_STATE.visualPrompt);
    }
  }, [isGameStarted]);

  const generateImage = async (prompt: string) => {
    try {
      const img = await generateSceneImage(prompt);
      if (img) setSceneImage(img);
    } catch (e) {
      console.error("Image gen failed", e);
    }
  };

  const handleAction = async () => {
    if (!input.trim() || isLoading) return;

    const action = input;
    setInput('');
    setIsLoading(true);

    // Add user action to UI immediately for responsiveness
    const tempHistory = [...history, { role: 'user', parts: [{ text: action }] }];

    try {
      // 1. Get Logic & Text
      const newState = await runGameTurn(tempHistory, action);
      setGameState(newState);

      // Update history
      const newHistory = [
          ...tempHistory, 
          { role: 'model', parts: [{ text: JSON.stringify(newState) }] } // Storing state as text for context
      ];
      setHistory(newHistory);

      // 2. Generate Image in parallel (or after, depending on preference. Parallel is faster)
      generateImage(newState.visualPrompt);

    } catch (error) {
      console.error(error);
      // Fallback UI or alert
    } finally {
      setIsLoading(false);
    }
  };

  const startGame = () => {
      setIsGameStarted(true);
  };

  if (!isGameStarted) {
      return (
          <div className="h-full w-full flex flex-col items-center justify-center p-8 text-center bg-[url('https://images.unsplash.com/photo-1535868463750-c78d9543614f?q=80&w=2676&auto=format&fit=crop')] bg-cover bg-center relative">
