                </p>
                <button 
                    onClick={startGame}
                    className="group relative px-10 py-5 bg-neon-blue text-black font-bold text-xl rounded-none clip-path-polygon hover:scale-105 transition-transform"
                    style={{ clipPath: 'polygon(10% 0, 100% 0, 100% 80%, 90% 100%, 0 100%, 0 20%)' }}
                >
                    <span className="flex items-center gap-3">
                        INITIALIZE LINK <Play fill="black" />
                    </span>
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="h-full w-full flex flex-col lg:flex-row bg-[#050508] overflow-hidden">

        {/* Left Panel: Visuals & Stats (Fixed) */}
        <div className="lg:w-1/2 flex flex-col h-1/2 lg:h-full border-r border-white/10 relative group">

            {/* Main Image Layer */}
            <div className="flex-1 relative overflow-hidden bg-black">
                {sceneImage ? (
                    <img 
                        src={sceneImage} 
                        alt="Current Scene" 
                        className="w-full h-full object-cover transition-opacity duration-1000 animate-in fade-in"
                    />
                ) : (
                    <div className="w-full h-full flex items-center justify-center bg-gray-900 animate-pulse">
                        <span className="text-neon-blue font-mono text-sm">RENDERING REALITY STREAM...</span>
                    </div>
                )}

                {/* Location Badge */}
                <div className="absolute top-6 left-6 bg-black/70 backdrop-blur border border-neon-blue/30 px-4 py-2 flex items-center gap-2 rounded-sm">
                    <MapPin size={16} className="text-neon-blue" />
                    <span className="text-white font-bold tracking-widest uppercase text-sm">{gameState.location}</span>
                </div>

                {/* Loading Overlay */}
                {isLoading && (
                    <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-20">
                        <div className="flex flex-col items-center">
                            <div className="w-16 h-16 border-4 border-t-neon-blue border-r-transparent border-b-neon-purple border-l-transparent rounded-full animate-spin mb-4"></div>
                            <span className="text-xs text-white tracking-[0.2em] animate-pulse">CALCULATING PROBABILITIES</span>
                        </div>
