                        title="Voice Input"
                    >
                        {isListening ? <MicOff size={18} /> : <Mic size={18} />}
                    </button>

                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleManualSubmit()}
                        placeholder={isListening ? t.listening : (isLoading ? t.processing : t.enterCmd)}
                        disabled={gameState.gameOver || isLoading}
                        className="w-full bg-transparent border-none text-white text-sm py-3 focus:ring-0 placeholder-gray-600 font-mono"
                        autoFocus
                    />
                    <button 
                        onClick={handleManualSubmit}
                        onMouseEnter={() => sfx.playHover()}
                        disabled={!input.trim() || isLoading || gameState.gameOver}
                        className="px-4 text-neon-blue hover:text-white disabled:opacity-30 disabled:hover:text-neon-blue transition-colors"
                    >
                        <Send size={18} />
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default StoryEngine;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPCMBlob, decodeBase64, decodeAudioData } from '../services/utils';
import { Mic, MicOff, Activity, Radio, AlertCircle } from 'lucide-react';

const API_KEY = process.env.API_KEY || '';

const LiveAvatar: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'active' | 'error'>('idle');
  const [isSpeaking, setIsSpeaking] = useState(false); // Visualizer trigger
  const [errorMessage, setErrorMessage] = useState<string>('');

  // Refs for audio handling to persist across renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  const cleanup = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
    }

    // Stop all playing sources
    sourcesRef.current.forEach(source => {
        try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();

    // Close audio contexts
    if (audioContextRef.current) audioContextRef.current.close();
    if (inputContextRef.current) inputContextRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());

    audioContextRef.current = null;
    inputContextRef.current = null;
    streamRef.current = null;
    sessionRef.current = null;

    setIsConnected(false);
    setStatus('idle');
    setIsSpeaking(false);
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  const startSession = async () => {
    try {
      setStatus('connecting');
      setErrorMessage('');

      const ai = new GoogleGenAI({ apiKey: API_KEY });

      // Check if browser supports getUserMedia
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Your browser does not support audio input.");
      }

      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err: any) {
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
            throw new Error("Microphone permission denied. Please allow access.");
        } else if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
            throw new Error("No microphone found. Please connect a device.");
        } else {
            throw new Error("Could not access microphone: " + err.message);
        }
      }

      streamRef.current = stream;

      // Setup Audio Output
      const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputAudioContext;
      const outputNode = outputAudioContext.createGain();
      outputNode.connect(outputAudioContext.destination);

      // Setup Audio Input
      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inputAudioContext;

      const source = inputAudioContext.createMediaStreamSource(stream);
      const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

      nextStartTimeRef.current = 0;

      // Connect to Gemini Live API
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: "You are 'Nova', a high-energy, futuristic AI companion in the OmniVerse. You are enthusiastic, helpful, and love creativity. Keep responses concise and engaging.",
        },
        callbacks: {
            onopen: () => {
                setStatus('active');
                setIsConnected(true);

                // Connect microphone stream
                scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    const pcmBlob = createPCMBlob(inputData);

                    sessionPromise.then((session) => {
                        session.sendRealtimeInput({ media: pcmBlob });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;

                if (base64Audio) {
                    setIsSpeaking(true);
                    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);

                    const audioBuffer = await decodeAudioData(
                        decodeBase64(base64Audio),
                        outputAudioContext,
                        24000,
                        1
                    );

                    const sourceNode = outputAudioContext.createBufferSource();
                    sourceNode.buffer = audioBuffer;
                    sourceNode.connect(outputNode);

                    sourceNode.addEventListener('ended', () => {
                        sourcesRef.current.delete(sourceNode);
                        if (sourcesRef.current.size === 0) setIsSpeaking(false);
                    });

                    sourceNode.start(nextStartTimeRef.current);
                    nextStartTimeRef.current += audioBuffer.duration;
                    sourcesRef.current.add(sourceNode);
                }

                if (message.serverContent?.interrupted) {
                    sourcesRef.current.forEach(s => s.stop());
                    sourcesRef.current.clear();
                    nextStartTimeRef.current = 0;
                    setIsSpeaking(false);
                }
            },
            onclose: () => {
                setStatus('idle');
                setIsConnected(false);
            },
            onerror: (err) => {
                console.error("Session Error:", err);
            }
        }
      });

      sessionRef.current = await sessionPromise;

    } catch (e: any) {
      console.error("Failed to connect:", e);
      setErrorMessage(e.message || "Connection failed");
      setStatus('error');
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full w-full p-8 bg-black/40 backdrop-blur-md rounded-3xl border border-white/10 shadow-[0_0_50px_rgba(0,243,255,0.1)]">

        {/* Visualizer Circle */}
        <div className={`relative w-64 h-64 mb-8 flex items-center justify-center rounded-full transition-all duration-500 ${isSpeaking ? 'scale-110 shadow-[0_0_80px_#00f3ff]' : 'shadow-[0_0_20px_rgba(255,255,255,0.1)]'}`}>
            <div className={`absolute inset-0 rounded-full border-4 border-dashed border-neon-blue ${status === 'connecting' ? 'animate-spin' : ''}`}></div>
            <div className="absolute inset-4 rounded-full bg-gradient-to-tr from-gray-900 to-black flex items-center justify-center overflow-hidden">
                {status === 'active' ? (
                     <div className="w-full h-16 flex items-center justify-center gap-2">
                        {[1,2,3,4,5].map(i => (
                            <div key={i} className={`w-3 bg-neon-blue rounded-full transition-all duration-100 ${isSpeaking ? 'animate-[pulse_0.5s_ease-in-out_infinite]' : 'h-2'}`} style={{ height: isSpeaking ? `${Math.random() * 40 + 10}px` : '4px', animationDelay: `${i * 0.1}s` }} />
                        ))}
                     </div>
                ) : (
                    <Activity className="w-16 h-16 text-gray-600" />
                )}
            </div>
        </div>

        <h2 className="text-3xl font-bold mb-2 bg-clip-text text-transparent bg-gradient-to-r from-neon-blue to-neon-purple">
            Nova Live
        </h2>
        <p className="text-gray-400 mb-8 text-center max-w-md">
            Your real-time AI companion. Talk naturally to brainstorm ideas, ask questions, or just hang out.
        </p>

        {status === 'error' && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/50 rounded-xl flex items-center gap-3 text-red-200 max-w-md animate-pulse">
                <AlertCircle size={24} className="text-red-500 flex-shrink-0" />
                <span className="text-sm font-medium">{errorMessage}</span>
            </div>
        )}

        {!isConnected ? (
            <button
                onClick={startSession}
                disabled={status === 'connecting'}
                className="group relative px-8 py-4 bg-white text-black font-bold rounded-full overflow-hidden hover:scale-105 transition-transform disabled:opacity-50 disabled:cursor-not-allowed"
            >
                <div className="absolute inset-0 bg-gradient-to-r from-neon-blue to-neon-purple opacity-0 group-hover:opacity-100 transition-opacity" />
                <div className="relative flex items-center gap-2 z-10 group-hover:text-white">
                    <Mic size={24} />
                    <span>{status === 'connecting' ? 'Initializing...' : 'Start Voice Chat'}</span>
                </div>
            </button>
        ) : (
            <button
                onClick={cleanup}
                className="px-8 py-4 bg-red-500/20 text-red-500 border border-red-500 rounded-full font-bold hover:bg-red-500 hover:text-white transition-all flex items-center gap-2"
            >
                <MicOff size={24} />
                <span>Disconnect</span>
            </button>
        )}

        {isConnected && (
            <div className="mt-6 flex items-center gap-2 text-xs text-neon-blue animate-pulse">
                <Radio size={12} />
                LIVE CONNECTION SECURE
            </div>
        )}
    </div>
  );
};

export default LiveAvatar;

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { decodeBase64, decodeAudioData } from "./utils";
import { GameState, Language } from "../types";

const API_KEY = process.env.API_KEY || '';

const getAI = () => new GoogleGenAI({ apiKey: API_KEY });

// --- IMAGE EDITING ---
export const editImageWithGemini = async (base64Image: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: mimeType } },
        { text: prompt || "Enhance this image" },
      ],
    },
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("No image returned.");
};

// --- VIDEO ANALYSIS ---
export const analyzeVideoWithGemini = async (base64Video: string, mimeType: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Video, mimeType: mimeType } },
        { text: prompt || "Analyze this video in detail." },
      ],
    },
  });
  return response.text || "No analysis generated.";
};

// --- AUDIO TRANSCRIPTION ---
export const transcribeAudioWithGemini = async (base64Audio: string, mimeType: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Audio, mimeType: mimeType } },
        { text: "Transcribe the audio exactly as spoken." },
      ],
    },
  });
  return response.text || "Transcription failed.";
};

// --- TTS ---
export const generateSpeechWithGemini = async (text: string, voiceName: 'Kore' | 'Puck' | 'Fenrir' | 'Zephyr' = 'Kore'): Promise<void> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } } },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio generated");

    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    const outputAudioContext = new AudioContextClass({ sampleRate: 24000 });
    const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), outputAudioContext, 24000, 1);
    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();
  } catch (e) {
    console.error("TTS Error:", e);
  }
};

// --- GAME ENGINE (OmniVerse Core) ---

export const generateSceneImage = async (prompt: string): Promise<string> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: `Video game concept art, cyberpunk, sci-fi, high resolution, cinematic lighting, 8k, detailed: ${prompt}` },
        ],
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
  } catch (e) {
    console.warn("Image Gen Error:", e);
    return "";
  }
  return ""; 
};

export const runGameTurn = async (history: any[], userAction: string, language: Language = 'en'): Promise<GameState> => {
  const ai = getAI();

  const langInstruction = language === 'es' 
    ? "IMPORTANT: Output language MUST be SPANISH (Español)." 
    : "Output language must be English.";

  const context = `You are the OmniVerse Core, a merciless AI Game Master running a Sci-Fi RPG.

  Current Action: ${userAction}

  Instructions:
  1. Update the game state based on the action.
  2. Keep narrative concise, edgy, and immersive (max 3 sentences).
  3. **CRITICAL**: Always end the narrative with a hook, a threat, or a question to prompt the player's next move. Do not let the story stall.
  4. 'visualPrompt' MUST be a visual description only (English), no UI text.
  5. If the player does something fatal, set gameOver to true.
  6. ${langInstruction}
  `;

  try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [
            ...history,
            { role: 'user', parts: [{ text: context }] }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              location: { type: Type.STRING },
              health: { type: Type.INTEGER },
              inventory: { type: Type.ARRAY, items: { type: Type.STRING } },
              narrative: { type: Type.STRING },
              visualPrompt: { type: Type.STRING },
              gameOver: { type: Type.BOOLEAN },
            },
            required: ["location", "health", "inventory", "narrative", "visualPrompt", "gameOver"],
          },
        },
      });

      const jsonText = response.text || "{}";
      return JSON.parse(jsonText) as GameState;

  } catch (e) {
      console.error("Game Logic Error:", e);
      return {
          location: language === 'es' ? "Sector Desconocido" : "Unknown Sector",
          health: 50,
          inventory: ["Glitched Data"],
          narrative: language === 'es' 
            ? "ERROR DE SISTEMA // SEÑAL INTERRUMPIDA. La simulación parpadea. Reintenta tu comando." 
            : "SYSTEM ERROR // SIGNAL INTERRUPTED. The reality simulation flickered. Please retry your last command.",
          visualPrompt: "Glitch art, static noise, corrupted data, dark cyberpunk",
          gameOver: false
      };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { runGameTurn, generateSceneImage, generateSpeechWithGemini } from '../services/gemini';
import { GameState, Language } from '../types';
import { sfx } from '../services/audio';
import { Send, Shield, MapPin, Package, Skull, Play, Terminal, Zap, Eye, Mic, MicOff, Volume2, VolumeX } from 'lucide-react';

interface StoryEngineProps {
  lang: Language;
}

const StoryEngine: React.FC<StoryEngineProps> = ({ lang }) => {
  // Translations
  const t = {
    initLoc: lang === 'es' ? "Sector 4 [Subterráneo]" : "Sector 4 [Underground]",
    initInv: lang === 'es' ? ["Tarjeta ID", "Cuchillo"] : ["ID Card", "Combat Knife"],
    initNar: lang === 'es' 
        ? "SECUENCIA_INICIO: Estás bajo la lluvia ácida. Las luces de neón se reflejan en los charcos. Escuchas pasos metálicos pesados acercándose por el callejón. Tienes un cuchillo y una tarjeta ID robada. ¿Corres o te escondes?"
        : "INIT_SEQUENCE: You stand in the acid rain. The neon lights reflect in the puddles. You hear heavy metallic footsteps approaching down the alley. You have a knife and a stolen ID card. Do you run or hide?",
    visualPrompt: "Dark cyberpunk alleyway, heavy acid rain, neon lights reflection, metallic texture, first person perspective, cinematic",
    startBtn: lang === 'es' ? "INICIAR LINK" : "INITIALIZE",
    immersion: lang === 'es' ? "Inmersión" : "Immersion",
    strategy: lang === 'es' ? "Estrategia" : "Strategy",
    survival: lang === 'es' ? "Supervivencia" : "Survival",
    visualizing: lang === 'es' ? "VISUALIZANDO..." : "VISUALIZING...",
    integrity: lang === 'es' ? "Integridad" : "Suit Integrity",
    inspect: lang === 'es' ? "Inspeccionar" : "Inspect",
    gear: lang === 'es' ? "Equipo" : "Gear",
    processing: lang === 'es' ? "PROCESANDO..." : "PROCESSING...",
    enterCmd: lang === 'es' ? "TU ACCIÓN..." : "YOUR ACTION...",
    critFail: lang === 'es' ? "FALLO CRÍTICO" : "CRITICAL FAILURE",
    reboot: lang === 'es' ? "REINICIAR SISTEMA" : "REBOOT SYSTEM",
    listening: lang === 'es' ? "ESCUCHANDO..." : "LISTENING...",
    actions: {
        inspect: lang === 'es' ? "Mirar alrededor" : "Look around",
        gear: lang === 'es' ? "Revisar inventario" : "Check inventory"
    }
  };

  const [gameState, setGameState] = useState<GameState>({
      location: t.initLoc,
      health: 100,
      inventory: t.initInv,
      narrative: t.initNar,
      visualPrompt: t.visualPrompt,
      gameOver: false
  });

  const [history, setHistory] = useState<any[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isNarratorOn, setIsNarratorOn] = useState(false); // TTS Toggle
  const [sceneImage, setSceneImage] = useState<string | null>(null);
  const [isGameStarted, setIsGameStarted] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initial Scene
  useEffect(() => {
    if (isGameStarted && !sceneImage) {
        generateImage(t.visualPrompt);
        if (isNarratorOn) {
            generateSpeechWithGemini(t.initNar, lang === 'es' ? 'Kore' : 'Fenrir');
        }
    }
  }, [isGameStarted]);

  // Scroll to bottom only when history updates
  useEffect(() => {
    if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history]);

  const generateImage = async (prompt: string) => {
    try {
      const img = await generateSceneImage(prompt);
      if (img) setSceneImage(img);
    } catch (e) {
      console.error("Image gen failed", e);
    }
  };

  const executeTurn = async (actionText: string) => {
    if (isLoading || gameState.gameOver) return;

    sfx.playClick();
    setIsLoading(true);
    const tempHistory = [...history, { role: 'user', parts: [{ text: actionText }] }];

    try {
      const newState = await runGameTurn(tempHistory, actionText, lang);
      sfx.playSuccess();
      setGameState(newState);

      const newHistory = [
          ...tempHistory, 
          { role: 'model', parts: [{ text: JSON.stringify(newState) }] } 
      ];
      setHistory(newHistory);

      // Narrative Voice
      if (isNarratorOn && newState.narrative) {
          generateSpeechWithGemini(newState.narrative, lang === 'es' ? 'Kore' : 'Fenrir');
      }

      // Visuals
      generateImage(newState.visualPrompt);
    } catch (error) {
      sfx.playError();
      console.error("Critical Failure:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleManualSubmit = () => {
    if (!input.trim()) return;
    executeTurn(input);
    setInput('');
  };

  const toggleMic = () => {
      if (isListening) {
          setIsListening(false);
          return;
      }

      if (!('webkitSpeechRecognition' in window)) {
          alert("Voice input requires a Chromium browser (Chrome/Edge).");
          return;
      }

      const SpeechRecognition = (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.lang = lang === 'es' ? 'es-ES' : 'en-US';
      recognition.continuous = false;
      recognition.interimResults = false;

      recognition.onstart = () => {
          setIsListening(true);
          sfx.playHover();
      };

      recognition.onend = () => {
          setIsListening(false);
      };

      recognition.onerror = (event: any) => {
          console.error("Speech recognition error", event.error);
          setIsListening(false);
          sfx.playError();
      };

      recognition.onresult = (event: any) => {
          const transcript = event.results[0][0].transcript;
          setInput(transcript);
          sfx.playSuccess();
          // AUTO SUBMIT FOR "SEGUIMIENTO" (Flow)
          setTimeout(() => {
             executeTurn(transcript);
             setInput('');
          }, 500);
      };

      recognition.start();
  };

  const startGame = () => {
      sfx.playSuccess();
      setIsGameStarted(true);
  };

  // --- WELCOME SCREEN ---
  if (!isGameStarted) {
      return (
          <div className="h-full w-full flex flex-col items-center justify-center relative overflow-hidden bg-black select-none">
              <div className="absolute inset-0 bg-grid-pattern opacity-30 bg-[size:30px_30px] animate-[pulse_4s_infinite]"></div>

              {/* Central Box */}
              <div className="z-10 flex flex-col items-center p-12 bg-black/50 backdrop-blur-sm border border-neon-blue/20 rounded-lg relative">
                 <div className="absolute -top-2 -left-2 w-4 h-4 border-t-2 border-l-2 border-neon-blue"></div>
                 <div className="absolute -bottom-2 -right-2 w-4 h-4 border-b-2 border-r-2 border-neon-blue"></div>

                <h1 className="text-6xl md:text-8xl font-black text-white mb-2 tracking-tighter drop-shadow-[0_0_15px_rgba(0,243,255,0.5)] font-sans">
                    CORE<span className="text-neon-blue">.</span>SYS
                </h1>

                <div className="flex items-center gap-4 text-gray-400 font-mono text-xs tracking-[0.3em] uppercase mb-12">
                     <span>{t.immersion}</span>
                     <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                     <span>{t.strategy}</span>
                     <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                     <span>{t.survival}</span>
                </div>

                 {/* Enable Narrator Toggle on Start */}
                 <div className="flex items-center gap-2 mb-8 cursor-pointer" onClick={() => setIsNarratorOn(!isNarratorOn)}>
                    <div className={`w-5 h-5 border rounded flex items-center justify-center ${isNarratorOn ? 'bg-neon-blue border-neon-blue' : 'border-gray-500'}`}>
                        {isNarratorOn && <div className="w-3 h-3 bg-black rounded-sm" />}
                    </div>
                    <span className="text-sm text-gray-400 uppercase tracking-widest flex items-center gap-2">
                        {isNarratorOn ? <Volume2 size={14}/> : <VolumeX size={14}/>} 
                        {lang === 'es' ? 'Activar Voz Narradora' : 'Enable Narrator Voice'}
                    </span>
                 </div>

                <button 
                    onClick={startGame}
