                        disabled={!input.trim() || isLoading || gameState.gameOver}
                        className="px-4 text-neon-blue hover:text-white disabled:opacity-30 disabled:hover:text-neon-blue transition-colors"
                    >
                        <Send size={18} />
                    </button>
                </div>
            </div>
        </div>
    </div>
