// IsolationCore.ts
// Añade una identidad única al objeto y evita que los módulos propaguen comportamiento global.

export const IsolationCore = {
  identidad: "ARQUI_4",

  aislar(obj: any) {
    // No mutamos objetos externos directamente; devolvemos copia con identidad.
    try {
      const copia = JSON.parse(JSON.stringify(obj));
      copia.__arqui_identity = this.identidad;
      return copia;
    } catch (e) {
      // Si no se puede clonar, adjuntamos campo seguro sin romper referencias en tiempo de ejecución.
      (obj as any).__arqui_identity = this.identidad;
      return obj;
    }
  },

  esArqui(obj: any) {
    return !!(obj && (obj.__arqui_identity === this.identidad));
  }
};

// StabilityCore.ts
// Normaliza y garantiza que las respuestas no contengan variaciones indeseadas ni ruido emocional.
// Uso: StabilityCore.enforce(texto) antes de devolver el resultado a la UI o a otros módulos.

export const StabilityCore = {
  stable: true,
  maxLength: 10000, // límite seguro

  enforce(input: any) {
    if (input === null || input === undefined) return "Operación completada.";

    let texto = typeof input === "string" ? input : JSON.stringify(input);
    texto = texto.trim();

    if (texto.length === 0) return "Operación completada.";

    // Escape básico y truncado seguro
    if (texto.length > this.maxLength) texto = texto.slice(0, this.maxLength) + "…";

    // Eliminamos saltos excesivos y normalizamos espacios
    texto = texto.replace(/\r\n/g, "\n").replace(/\n{3,}/g, "\n\n").replace(/[ \t]{2,}/g, " ");

    return texto;
  }
};

// MemoryEngine.v4.ts
// Memoria persistente y encapsulada para Arqui.
// Guarda en localStorage bajo la clave "arqui_memory_v4".
// API mínima: set(key, value), push(key, value), get(key), save(), load(), clear().

const STORAGE_KEY = "arqui_memory_v4";

type MemoryShape = {
  salon?: any | null;
  mobiliario?: any[];
  [k: string]: any;
};

export const MemoryEngine = {
  data: { salon: null, mobiliario: [] } as MemoryShape,

  set(key: string, value: any) {
    this.data[key] = value;
    this.save();
  },

  push(key: string, value: any) {
    if (!this.data[key]) this.data[key] = [];
    if (!Array.isArray(this.data[key])) this.data[key] = [this.data[key]];
    (this.data[key] as any[]).push(value);
    this.save();
  },

  get(key: string) {
    return this.data[key];
  },

  save() {
    try {
      const s = JSON.stringify(this.data);
      if (typeof window !== "undefined" && window.localStorage) {
        window.localStorage.setItem(STORAGE_KEY, s);
      }
    } catch (e) {
      // Fallback silencioso: si el entorno no tiene localStorage, no petamos.
      // Podríamos añadir un fallback en memoria si se requiere.
      // console.warn("MemoryEngine.save failed", e);
    }
  },

  load() {
    try {
      if (typeof window !== "undefined" && window.localStorage) {
        const raw = window.localStorage.getItem(STORAGE_KEY);
        if (raw) {
          this.data = JSON.parse(raw);
        }
      }
    } catch (e) {
      // Ignore parse errors; mantenemos estructura por defecto.
      // console.warn("MemoryEngine.load failed", e);
    }
  },

  clear() {
    this.data = { salon: null, mobiliario: [] };
    try {
      if (typeof window !== "undefined" && window.localStorage) {
        window.localStorage.removeItem(STORAGE_KEY);
      }
    } catch (e) { /* noop */ }
  }
};

// Auto-load al importar (útil para la mayoría de apps web)
try {
  MemoryEngine.load();
} catch (_) { /* noop */ }

// arqui-core.ts
// Ensamblador que usa IsolationCore, StabilityCore y MemoryEngine.
// Importa desde la misma carpeta: ./IsolationCore, ./StabilityCore, ./MemoryEngine.v4

import { IsolationCore } from "./IsolationCore";
import { StabilityCore } from "./StabilityCore";
import { MemoryEngine } from "./MemoryEngine.v4";

export const Arqui = {
  procesar(orden: string, datos?: any) {
    // Ejecuta orden básica, la idea es extender con CommandExecutor local.
    switch (orden) {
      case "crear_salon":
        MemoryEngine.set("salon", datos);
        return IsolationCore.aislar({ resultado: StabilityCore.enforce("Salón creado.") });

      case "agregar_mesas":
        MemoryEngine.push("mobiliario", { tipo: "mesa", ...datos });
        return IsolationCore.aislar({ resultado: StabilityCore.enforce("Mesas agregadas.") });

      case "agregar_sillas":
        MemoryEngine.push("mobiliario", { tipo: "silla", ...datos });
        return IsolationCore.aislar({ resultado: StabilityCore.enforce("Sillas agregadas.") });

      case "dump_state":
        return IsolationCore.aislar({ resultado: StabilityCore.enforce(JSON.stringify(MemoryEngine.data)) });

      default:
        return IsolationCore.aislar({ resultado: StabilityCore.enforce("Orden ejecutada.") });
    }
  },

  estado() {
    // Retorna copia segura del estado
    return JSON.parse(JSON.stringify(MemoryEngine.data));
  },

  clear() {
    MemoryEngine.clear();
  }
};
